var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"여기는 알파. COM-1에서 침식파 발원지를 포착했습니다.","JPN":"こちらアルファ。COM-1で侵食波発源地を捕捉しました。","ENG":"Alpha here. COM-1 has eyes on the source of the Corruption Ray.","TWN":"這裡是阿爾法。在COM-1探測到了侵蝕波的源頭。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"데이터베이스에 따르면 원인은 제 3종 침식체의 고치로 추정됩니다.","JPN":"データベースによると、原因は第3種侵食体の繭だと推定されます。","ENG":"According to the database, it appears to come from a cocoon of Category 3 C.O.","TWN":"根據資料庫推測，原因是3級侵蝕體的繭。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"확인했습니다. 교전수칙에 의거. 침식억제기와 T3 중화기 투입. 즉시 소각절차에 들어갑니다.","JPN":"確認しました。交戦規則に基づき、侵食抑制器とT3重火器投入。即時、焼却手続きに入ります。","ENG":"Copy that. Based on the applicable ROE, deploy corruption suppressors and T3 heavy weapons to commence incineration.","TWN":"已確認。根據交戰守則，投入侵蝕抑制器和T3級重火器，立即進行焚毀程序。"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"알겠습니다. 그럼 공격을......","JPN":"わかりました。では攻撃を……","ENG":"Wilco. Preparing to engage...","TWN":"我知道了。那就攻擊……"},"stage":{"bg":"HELI_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"엇?! 이 소리는......?","JPN":"えっ！？この音は……？","ENG":"Huh?! What's that sound?","TWN":"呃？！這聲音是……？"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PILOT_VOICE_NULL_NULL","text":{"KOREA":"급성 침식 반응 감지! 고치가 움직입니다!","JPN":"急性侵食反応感知！　繭が動き出しました！","ENG":"Acute Corruption response detected! The cocoon is moving!","TWN":"偵測到急性侵蝕反應！繭動起來了！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이런! 타이밍이 안 좋긴 하지만 당황할 필요 없습니다.","JPN":"しまった！　タイミングが悪いですが、慌てる必要はありません。","ENG":"Dang it! This is bad timing, but there's no need to panic.","TWN":"有這種事！雖然這個時機有點不妙，不過沒必要慌張。"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"분명 교전수칙에서도 이런 상황에 대응하는 매뉴얼이......","JPN":"きっと交戦規則にもこういった状況に対応するマニュアルが……","ENG":"I'm sure there's a standard operating procedure for this situation as well...","TWN":"我記得交戰守則裡有寫，對應這種情況的指南……"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"매뉴얼은 됐어, 카일.","JPN":"マニュアルはいい、カイル。","ENG":"Forget about the procedure, Kyle.","TWN":"不用查交戰守則了，凱爾。"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어차피 녀석이 깨어난 이상, 정면대결은 피할 수 없잖아?","JPN":"どうせ奴が目覚めた以上、真っ向勝負は避けられないだろ？","ENG":"We'll have no choice but to fight it head on now that it's awake.","TWN":"反正那傢伙已經蘇醒了，正面交鋒是不可避免的吧？"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"기다리십시오, 대령님. 항상 그런 식으로 무모하게 행동하시는 건......!","JPN":"待ってください、大佐。いつもそんなふうにむやみに行動されては……！","ENG":"Wait, Colonel. That sounds too reckless!","TWN":"請等一下，上校。您總是這樣魯莽行動……！"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"카일, 완벽한 계획을 세우는 것도 좋지만.....","JPN":"カイル、完璧な計画を立てることもいいが……","ENG":"Kyle, as nice it would be to have a perfect plan...","TWN":"凱爾，制定完美的計畫是很不錯……"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......망설이다 후회했을 땐 늦는 법이라고.","JPN":"……ためらって後悔した時には遅いんだよ。","ENG":"It'll be too late if we hesitate.","TWN":"……但猶豫就會後悔，那樣就太遲了。"},"stage":{"bg":"HELI_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ELECTRIC_BIG"},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"저, 저거 침식체야? 저렇게 큰 건 들어본 적도 없어!","JPN":"あ、あれが侵食体！？　あんなに大きいのは見たこともない！","ENG":"I-is that a C.O.? I've never even heard of anything that big!","TWN":"那、那是侵蝕體嗎？我可沒聽過有這麼大的侵蝕體！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_30"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"모두 도망쳐!","JPN":"みんな、逃げて！","ENG":"Run, everyone!","TWN":"大家快逃！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L23_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"으윽! 나, 나 다리가 끼어서 안 움직여!","JPN":"ううっ！　わ、私、足が挟まって動けないよ！","ENG":"Eek! M-my leg is stuck! I can't move!","TWN":"呃呃！我，我的腿被夾住了，動不了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_05"},{"id":"L24_1","type":"dialog","speaker":"BOY_EXTRA_NULL_NULL","text":{"KOREA":"기다려! 지금 꺼내줄게!","JPN":"待って！　今、助けてあげるから！","ENG":"Wait! I'll get you out!","TWN":"不要緊！我這就來幫妳！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BOY_EXTRA_NULL_NULL","text":{"KOREA":"크윽......! 내 힘으론 안되겠어.","JPN":"くうっ……！　僕の力じゃ無理かも。","ENG":"Hngh! I'm not strong enough to get you out...","TWN":"唔……！光靠我一個人沒辦法。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"꺄악! 괴물이 오고 있어!","JPN":"きゃあ！　化け物が近づいてる！","ENG":"Aaah! The monster's coming!","TWN":"呀啊！怪物過來了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MONSTER_MOVEMENT_03"},{"id":"L31_1","type":"dialog","speaker":"BOY_EXTRA_NULL_NULL","text":{"KOREA":"헉, 헉! 누, 누가......","JPN":"はぁ、はぁ！　だ、誰か……","ENG":"*Huff... Huff...* S-somebody...","TWN":"哇，哇！誰，誰來……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BOY_EXTRA_NULL_NULL","text":{"KOREA":"누가 좀 도와줘요!!!","JPN":"誰か助けてください！！！","ENG":"Please help!","TWN":"誰來幫幫我！！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BOY_EXTRA_NULL_NULL","text":{"KOREA":"사, 사람이......","JPN":"ひ、人が……","ENG":"A m-man...","TWN":"有，有人……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BOY_EXTRA_NULL_NULL","text":{"KOREA":"하늘에서 떨어졌어?","JPN":"空から落ちた？","ENG":"Just fell out from the sky?","TWN":"從天上掉下來了？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐야. 한 대 맞고 뻗었어? 금방 깨어난 녀석이라 약한 건가?","JPN":"何だ、一発で倒れちまった。目覚めたばかりの奴だから弱いのか？","ENG":"What the hell. One hit? That's all it took? Or was it weaker because it just came out of the cocoon?","TWN":"什麼，挨了一下就掛了啊？因為剛睡醒所以才這麼弱嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BOY_EXTRA_NULL_NULL","text":{"KOREA":"저, 저기......","JPN":"あ、あの……","ENG":"E-excuse me...","TWN":"那，那個……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......음?","JPN":"……うん？","ENG":"Hmm?","TWN":"……嗯？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"괜찮니, 꼬맹이들? 침식체 근처에서 있으면 위험하단다.","JPN":"君たち、大丈夫か？　侵食体の近くにいると危ないぞ。","ENG":"Are you alright, kids? It's dangerous around C.O.s, you know.","TWN":"沒受傷吧，小鬼們？這附近有侵蝕體，很危險。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BOY_EXTRA_NULL_NULL","text":{"KOREA":"네? ......네!","JPN":"はい？　……はい！","ENG":"Sorry? Oh, right!","TWN":"呃？……是的！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOY_EXTRA_NULL_NULL","text":{"KOREA":"......일어나, 가자.","JPN":"……さあ、起きて。行こう。","ENG":"Come on, let's go.","TWN":"……快起來，我們走。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GIRL_EXTRA_NULL_NULL","text":{"KOREA":"오, 오빠...... 저거 봐. 괴물이 빨갛게 익었어.","JPN":"お、お兄ちゃん……あれを見て。怪物が真っ赤になってる。","ENG":"L-look over there. The monster is cooked red.","TWN":"哥，哥哥……你看，怪物被烤得紅紅的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BAR1_NPC_NULL_NULL","text":{"KOREA":"그때 내가 그 광경을 내 두 눈으로 똑똑히 봤지.","JPN":"あの時、私はその光景をはっきり見たんだ。","ENG":"I swear, I saw it with my own two eyes.","TWN":"那時，我用這雙眼睛，清清楚楚看到了那一幕。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BAR1_NPC_NULL_NULL","text":{"KOREA":"그 시끄럽던 녀석이 비명도 못 지르고 풀썩 주저앉았다니까.","JPN":"あのうるさい奴が、悲鳴を上げることもなくへなへなと崩れてしまったんだよ。","ENG":"That loud obnoxious thing just went flop without so much as a scream.","TWN":"那個吵鬧的傢伙連聲慘叫都沒有就直接倒下了。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"푸하하하! 이 친구, 비약이 너무 심한데?","JPN":"プハハハ！　おいおい、飛躍しすぎだろう？","ENG":"Hah hah hah! You exaggerate too much!","TWN":"噗哈哈哈！這位朋友，你也太誇張了吧？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"카운터가 아무리 강하기로서니, 어떻게 주먹 한 방에 3종 침식체가 뻗겠어?","JPN":"いくらカウンターが強いとはいえ、一発殴っただけで第3種侵食体が倒れるなんてあり得ないんだよ。","ENG":"Sure, Counters may be strong, but how could anyone knock down a Category 3 with a single punch?","TWN":"制裁者再強大，也不可能一拳就打倒3級侵蝕體吧？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BAR3_NPC_NULL_NULL","text":{"KOREA":"그러게 말이야. 3종이 뉘집 개 이름인 줄 아는구만.","JPN":"そうだな。第3種はそんな簡単に倒せるものじゃないんだぜ。","ENG":"Tell me about it. Category 3's are no joke, I tell ya.","TWN":"就是啊。我聽了還以為是誰家狗叫“三級”呢。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BAR3_NPC_NULL_NULL","text":{"KOREA":"고작 카운터 한 명으로 그런 일이 가능하면 군대가 왜 필요해?","JPN":"たかがカウンター1人でそんなことが可能なら、軍なんか必要ないだろう？","ENG":"Why would we even need an army if a single Counter can pull that off?","TWN":"要是一個制裁者單槍匹馬就能做到這種事，還要軍隊幹嘛？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BAR1_NPC_NULL_NULL","text":{"KOREA":"그야 나도 믿기 힘들다는 건 알아! 하지만 진짜라니까!","JPN":"そりゃ、信じがたいのはわかるけど！　でも、本当だってば！","ENG":"I know it's hard to believe! But it really happened!","TWN":"我也知道這很難以置信！但這都是真的！"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"......이봐 당신들, 내기를 했다면 저 친구에게 돈을 주라고. 그 말은 사실이니까.","JPN":"……おい、君たち。もし賭けをしたのなら、あの人にお金を渡しなさい。その話は本当だ。","ENG":"Hey folks, if you bet on this, you owe that guy your money. Because he's telling the truth.","TWN":"……喂，如果你們在和他打賭的話，就乖乖認輸，把錢給這位朋友吧。因為他說的都是實話。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L18_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"음? 당신도 그걸 봤소?","JPN":"うん？　あんたもそれを見たのかい？","ENG":"Huh? Did you see it, too?","TWN":"咦？你也看到了嗎？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"그래. 3종을 때려잡았다는 그 친구.","JPN":"そうだ。第3種を叩き潰したというあのカウンターをね。","ENG":"That's right. That guy who took down the Category 3...","TWN":"沒錯。打倒3級的那位朋友十分強大。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"사실 전력을 다하면 4종 침식체도 해치울 수 있을 정도로 강하거든.","JPN":"実は、全力を尽くしたら第4種侵食体も片付けられるほど強いんだ。","ENG":"He's actually strong enough to take down a Category 4 if he puts his mind to it.","TWN":"要是他使出全力的話，連4級侵蝕體也能打倒。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"형씨, 아무리 그래도 허풍이 너무 심한 거 아냐?","JPN":"兄さんよ、いくら何でも誇張し過ぎだろ？","ENG":"Oh, come on. You don't expect us to believe that, do you?","TWN":"老兄，你吹牛吹過頭了吧？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BAR2_NPC_NULL_NULL","text":{"KOREA":"4종이라면 국가가 발칵 뒤집히는 수준이라고!","JPN":"第4種なら、国中が大騒ぎになるレベルだぜ！","ENG":"Category 4 is enough to turn an entire country upside down!","TWN":"4級，那可是足以毀滅國家的水準啊！"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"뭐, 나야 자네들이 믿건 말건 상관없어.","JPN":"まぁ、君たちが信じようが信じまいが私には関係ないけどね。","ENG":"Well, it doesn't matter if you believe me or not.","TWN":"愛信不信隨便你。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"하지만 이거 하나만은 확신하지.","JPN":"だが、これだけは確信する。","ENG":"There's one thing I know for sure though.","TWN":"但至少有一點我可以確認。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"어느 날, 당신 눈 앞에 4종 침식체가 나타난다면,","JPN":"ある日、君の目の前に第4種侵食体が現れたとしたら、","ENG":"One day, when a Category 4 appears in front of you...","TWN":"如果有一天，4級侵蝕體出現在你們面前。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"정말 그런 괴물 같은 친구가 곁에 있어주길 간절히 바라게 될 거라고 말이야.","JPN":"あの化け物みたいなカウンターがそばにいてくれればと、切に望むことになるだろう。","ENG":"You'll desperately wish someone unbelievably strong like him is nearby.","TWN":"你們一定會迫切希望，那種怪物一樣的傢伙能在自己身邊。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};